    // Mock adapterManager.getAdapter() to return a valid adapter
    // Mock meshCore.getProjectPath() to return undefined
    // POST /bindings with agentId: 'unknown-agent'
    // Expect 400 with error: "Agent 'unknown-agent' not found in mesh registry"
  });

  it('creates binding when adapter and agent both exist', async () => {
