Modify all three ThreadIdCodec implementations to accept an optional instance ID parameter that gets embedded in the subject prefix, enabling disambiguation between multiple instances of the same adapter type.

## Implementation

**File:** `packages/relay/src/lib/thread-id.ts`

### TelegramThreadIdCodec

Change from a readonly literal prefix to a constructor-computed prefix:

```typescript
export class TelegramThreadIdCodec implements ThreadIdCodec {
  readonly prefix: string;

  /**
   * @param instanceId - Optional adapter instance ID for multi-instance disambiguation.
   *   When provided, subjects include the instance ID segment:
   *   `relay.human.telegram.<instanceId>.<chatId>`. When omitted, produces
   *   legacy format: `relay.human.telegram.<chatId>`.
   */
  constructor(instanceId?: string) {
    this.prefix = instanceId
      ? `relay.human.telegram.${instanceId}`
      : 'relay.human.telegram';
  }

  encode(platformId: string, channelType: 'dm' | 'group'): string {
    if (channelType === 'group') {
      return `${this.prefix}.group.${platformId}`;
    }
    return `${this.prefix}.${platformId}`;
  }

  decode(subject: string): { platformId: string; channelType: 'dm' | 'group' } | null {
    return decodeSubject(this.prefix, subject);
  }
}
```

